import heapq

def dijkstra(graph, start):
    """graph: {node: [(neighbour, weight), ...]}"""
    if start not in graph:
        raise ValueError("Start node is not part of the graph.")

    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    prev = {node: None for node in graph}
    heap = [(0, start)]
    visited = set()

    while heap:
        d, u = heapq.heappop(heap)
        if u in visited:
            continue
        visited.add(u)
        for v, w in graph.get(u, []):
            # Check if v is even a known node key in the primary graph keys set 
            # to prevent KeyError if adjacency lists point outside defined nodes (though typically they shouldn't)
            if v not in dist:
                continue # Skip undefined neighbors

            if dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
                prev[v] = u
                heapq.heappush(heap, (dist[v], v))

    return dist, prev

def shortest_path(graph, start, end):
    # Note: We should use the full set of nodes from the graph keys/values 
    # if the graph structure is meant to capture all existing points. 
    # For now, sticking to the original implementation scope assuming `graph` defines all relevant nodes for distance calculation.
    if start not in graph or end not in graph:
        return None, float('inf')

    dist, prev = dijkstra(graph, start)
    if dist[end] == float('inf'):
        return None, float('inf')
    path = []
    node = end
    # Ensure node found is actually reachable/processed by dijkstra helper logic
    while node is not None and node in dist: 
        path.append(node)
        if node == start:
            break # Prevent infinite loops if graph connections are weird
        node = prev[node]
    return path, dist[end]

